import React, { useState, useRef } from "react";
import { useSwipeable } from "react-swipeable";
import WeatherOverlay from "./WeatherOverlay";

export default function WeatherApp() {
  const weatherCondition = "rain";
  const isDaytime = false;

  const cards = [
    { label: "Temperature", value: "36.2°C" },
    { label: "Humidity", value: "70%" },
    { label: "Wind Speed", value: "12 km/h" },
    { label: "UV Index", value: "5 (Moderate)" },
    { label: "Visibility", value: "10 km" },
    { label: "Pressure", value: "1012 hPa" },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);
  const [summaryMode, setSummaryMode] = useState(false);
  const longPressTimeout = useRef(null);
  const longPressed = useRef(false);

  const handlers = useSwipeable({
    onSwipedUp: () => {
      if (!summaryMode) setCurrentIndex((prev) => (prev + 1) % cards.length);
    },
    onSwipedDown: () => {
      if (!summaryMode) setCurrentIndex((prev) => (prev === 0 ? cards.length - 1 : prev - 1));
    },
    trackTouch: true,
    trackMouse: true,
  });

  const handleTouchStart = () => {
    longPressed.current = false;
    longPressTimeout.current = setTimeout(() => {
      longPressed.current = true;
      setSummaryMode(true);
    }, 500); // Only triggers if held 500ms
  };

  const handleTouchEnd = () => {
    clearTimeout(longPressTimeout.current);
    if (longPressed.current) {
      setSummaryMode(false); // Instantly return when releasing after hold
    } else {
      // Tap: next card
      if (!summaryMode) {
        setCurrentIndex((prev) => (prev + 1) % cards.length);
      }
    }
  };

  return (
    <div
      {...handlers}
      className="relative flex flex-col items-center justify-center min-h-screen overflow-hidden bg-white dark:bg-black"
    >
      {/* Background Overlay */}
      <WeatherOverlay weatherCondition={weatherCondition} isDaytime={isDaytime} />

      {/* Header */}
      <div className="text-center pt-6 z-10">
        <h1 className="text-4xl font-bold text-white drop-shadow-glow">
          Today in <span className="text-purple-400">Atlanta</span>
        </h1>
        <p className="text-lg text-white/70 mt-1 capitalize drop-shadow-glow">
          {weatherCondition}
        </p>
      </div>

      {/* Weather Cards */}
      <div className="flex-1 flex items-center justify-center z-10">
        <div className="relative">
          {!summaryMode ? (
            <div
              className="relative w-[200px] h-[140px] cursor-pointer"
              onTouchStart={handleTouchStart}
              onMouseDown={handleTouchStart}
              onTouchEnd={handleTouchEnd}
              onMouseUp={handleTouchEnd}
            >
              {cards.map((card, index) => (
                <div
                  key={index}
                  className={`absolute top-0 left-0 w-full h-full transition-all duration-500 ease-in-out ${
                    index === currentIndex
                      ? "z-20 opacity-100 scale-100"
                      : "z-0 opacity-0 scale-95"
                  } flex flex-col items-center justify-center bg-white/10 backdrop-blur-xl rounded-2xl shadow-xl ring-1 ring-white/20 border-t border-white/30`}
                >
                  <p className="text-sm font-semibold text-purple-300 drop-shadow-purple mb-1">
                    {card.label}
                  </p>
                  <p className="text-2xl font-bold text-purple-400 drop-shadow-purple">
                    {card.value}
                  </p>

                  {/* Dots */}
                  <div className="absolute bottom-1 left-1/2 transform -translate-x-1/2 flex space-x-1 mt-2">
                    {cards.map((_, idx) => (
                      <span
                        key={idx}
                        className={`w-2 h-2 rounded-full ${
                          idx === currentIndex
                            ? "bg-purple-400 scale-110"
                            : "bg-purple-300 opacity-30"
                        } transition-all duration-300`}
                      />
                    ))}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="grid grid-cols-1 gap-4 px-4 pt-4">
              {cards.map((card, idx) => (
                <div
                  key={idx}
                  style={{ animationDelay: `${idx * 100}ms` }}
                  className="opacity-0 animate-fade-in-down w-[200px] h-[100px] mx-auto flex flex-col items-center justify-center bg-white/10 backdrop-blur-xl rounded-2xl shadow-xl ring-1 ring-white/20 border-t border-white/30 transition-all duration-500"
                >
                  <p className="text-sm font-semibold text-purple-300 drop-shadow-purple mb-1">
                    {card.label}
                  </p>
                  <p className="text-xl font-bold text-purple-400 drop-shadow-purple">
                    {card.value}
                  </p>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Swipe Hint */}
      <div className="text-sm text-white/60 mb-4 z-10">
        {summaryMode ? "Release to return" : "Swipe up/down or hold"}
      </div>

      {/* Bottom Navigation */}
      <div className="h-20 fixed bottom-0 left-0 w-full bg-white/30 backdrop-blur-md border-t border-white/40 shadow-lg z-10 flex items-center justify-around rounded-t-2xl">
        {[
          { icon: "🌤", label: "Forecast" },
          { icon: "📡", label: "Radar" },
          { icon: "💬", label: "Community" },
          { icon: "🤖", label: "Weathy" },
        ].map((tab, idx) => (
          <button
            key={idx}
            className="flex flex-col items-center text-gray-800 hover:text-purple-500 transition duration-300"
          >
            <span className="text-xl">{tab.icon}</span>
            <span className="text-xs">{tab.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}
